1	type Cell = [row: number, col: number];
2	
3	function countNeighbors(cells: Cell[], row: number, col: number): number {
4	  return cells.filter(
5	    ([cellRow, cellCol]) =>
6	      Math.abs(cellRow - row) <= 1 &&
7	      Math.abs(cellCol - col) <= 1 &&
8	      !(cellRow === row && cellCol === col)
9	  ).length;
10	}
11	
12	export const nextGeneration = (cells: Cell[]): Cell[] =>
13	  cells.filter(([row, col]) =>
14	    [2, 3].includes(countNeighbors(cells, row, col))
15	  );
